                        setNewsCount(data);
                        /*changeFavicon(favIconAlert);*/
                    }
                }
            }
        });
    }

    function setNotiCookie(cookieName, cookieTime, data) {
        var date = new Date();
        date.setTime(date.getTime() + (cookieTime * 60 * 1000));
